#!/usr/bin/env python3
"""Build docs/index.html, docs/jobs.json, docs/schools.json from data/."""
from __future__ import annotations
import csv,json,re
from datetime import datetime,timezone
from pathlib import Path
ROOT=Path(__file__).resolve().parents[1]; SCHOOLS=ROOT/'data/schools.csv'; JOBS=ROOT/'data/jobs.json'; DOCS=ROOT/'docs'
def clean(s): return re.sub(r'\s+',' ',str(s or '')).strip()
def read_schools():
    if not SCHOOLS.exists(): return []
    with SCHOOLS.open(newline='',encoding='utf-8-sig') as f: rows=list(csv.DictReader(f))
    for r in rows:
        r['usnews_cs_rank']=clean(r.get('usnews_cs_rank') or r.get('usnews_rank')); r['school']=clean(r.get('school')); r['state']=clean(r.get('state')); r['location']=clean(r.get('location'))
    return rows
def read_jobs():
    if not JOBS.exists(): return []
    try:
        obj=json.loads(JOBS.read_text(encoding='utf-8')); return obj if isinstance(obj,list) else []
    except Exception: return []
def main():
    DOCS.mkdir(parents=True,exist_ok=True); schools=read_schools(); jobs=read_jobs(); updated=datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M UTC')
    (DOCS/'jobs.json').write_text(json.dumps(jobs,indent=2,ensure_ascii=False),encoding='utf-8'); (DOCS/'schools.json').write_text(json.dumps(schools,indent=2,ensure_ascii=False),encoding='utf-8')
    schools_json=json.dumps(schools,ensure_ascii=False); jobs_json=json.dumps(jobs,ensure_ascii=False)
    html=f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>CS Faculty Job Tracker</title><style>
:root{{--bg:#f6f7fb;--card:#fff;--text:#1f2937;--muted:#6b7280;--line:#e5e7eb;--accent:#2563eb}}body{{margin:0;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Helvetica,Arial,sans-serif;background:var(--bg);color:var(--text)}}header{{background:#111827;color:white;padding:28px 32px}}header h1{{margin:0 0 8px;font-size:28px}}header p{{margin:0;color:#d1d5db}}main{{max-width:1200px;margin:0 auto;padding:24px}}.stats{{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin-bottom:20px}}.stat{{background:var(--card);border:1px solid var(--line);border-radius:12px;padding:16px}}.stat b{{display:block;font-size:26px}}.tabs{{display:flex;gap:8px;margin:18px 0}}button{{border:1px solid var(--line);background:white;border-radius:8px;padding:10px 14px;cursor:pointer}}button.active{{background:var(--accent);color:white;border-color:var(--accent)}}.filters{{display:grid;grid-template-columns:2fr repeat(4,1fr);gap:10px;margin:16px 0}}input,select{{width:100%;box-sizing:border-box;padding:10px;border:1px solid var(--line);border-radius:8px;background:white}}.table-wrap{{overflow:auto;background:white;border:1px solid var(--line);border-radius:12px}}table{{width:100%;border-collapse:collapse;min-width:900px}}th,td{{padding:10px 12px;border-bottom:1px solid var(--line);text-align:left;vertical-align:top}}th{{background:#f9fafb;font-size:12px;text-transform:uppercase;color:var(--muted)}}a{{color:var(--accent);text-decoration:none}}.tag{{display:inline-block;padding:2px 7px;border-radius:999px;background:#eef2ff;margin:1px;font-size:12px}}.muted{{color:var(--muted)}}footer{{color:var(--muted);font-size:13px;margin-top:24px}}@media(max-width:800px){{.filters{{grid-template-columns:1fr}}}}</style></head><body><header><h1>CS Faculty Job Tracker</h1><p>U.S. News CS top-200 school list + public faculty job pages. Last built: {updated}</p></header><main><section class="stats"><div class="stat"><span class="muted">Schools tracked</span><b>{len(schools)}</b></div><div class="stat"><span class="muted">Job candidates</span><b>{len(jobs)}</b></div><div class="stat"><span class="muted">Open jobs</span><b>{sum(1 for j in jobs if j.get('status','open')=='open')}</b></div></section><div class="tabs"><button id="jobsTab" class="active" onclick="showTab('jobs')">Job openings</button><button id="schoolsTab" onclick="showTab('schools')">Top-200 schools</button></div><section class="filters"><input id="q" placeholder="Search school, title, state, field..." oninput="render()"><select id="state" onchange="render()"><option value="">All states</option></select><select id="rank" onchange="render()"><option value="">All ranks</option></select><select id="field" onchange="render()"><option value="">All fields</option></select><select id="status" onchange="render()"><option value="">All statuses</option></select></section><div class="table-wrap"><table id="table"><thead></thead><tbody></tbody></table></div><footer>This is a best-effort tracker built from public pages. Always verify deadlines and eligibility on the official posting page.</footer></main><script>
const SCHOOLS={schools_json}; const JOBS={jobs_json}; let tab='jobs';
function esc(s){{return String(s||'').replace(/[&<>"']/g,c=>({{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}}[c]));}}
function uniq(a){{return [...new Set(a.filter(Boolean))].sort((x,y)=>String(x).localeCompare(String(y),undefined,{{numeric:true}}));}}
function fill(id,vals){{const el=document.getElementById(id); while(el.options.length>1) el.remove(1); vals.forEach(v=>{{const o=document.createElement('option');o.value=v;o.textContent=v;el.appendChild(o);}});}}
function showTab(t){{tab=t;document.getElementById('jobsTab').classList.toggle('active',t==='jobs');document.getElementById('schoolsTab').classList.toggle('active',t==='schools');configure();render();}}
function configure(){{const d=tab==='jobs'?JOBS:SCHOOLS; fill('state',uniq(d.map(x=>x.state))); fill('rank',uniq(d.map(x=>x.usnews_cs_rank||x.school_rank))); fill('field',tab==='jobs'?uniq(JOBS.flatMap(x=>x.field||[])):[]); fill('status',tab==='jobs'?uniq(JOBS.map(x=>x.status||'open')):[]); document.getElementById('field').disabled=tab!=='jobs'; document.getElementById('status').disabled=tab!=='jobs';}}
function match(x){{const q=document.getElementById('q').value.toLowerCase().trim(), state=document.getElementById('state').value, rank=document.getElementById('rank').value, field=document.getElementById('field').value, status=document.getElementById('status').value; const hay=JSON.stringify(x).toLowerCase(); if(q&&!hay.includes(q))return false; if(state&&x.state!==state)return false; if(rank&&String(x.usnews_cs_rank||x.school_rank||'')!==rank)return false; if(tab==='jobs'&&field&&!(x.field||[]).includes(field))return false; if(tab==='jobs'&&status&&(x.status||'open')!==status)return false; return true;}}
function render(){{const thead=document.querySelector('#table thead'), tbody=document.querySelector('#table tbody'); tbody.innerHTML=''; if(tab==='jobs'){{thead.innerHTML='<tr><th>Position</th><th>School</th><th>USN Rank</th><th>Location</th><th>Field</th><th>Deadline</th><th>Status</th></tr>'; JOBS.filter(match).forEach(j=>{{const fields=(j.field||[]).map(f=>`<span class="tag">${{esc(f)}}</span>`).join(' '); const title=j.source_url?`<a href="${{esc(j.source_url)}}" target="_blank" rel="noopener">${{esc(j.title)}}</a>`:esc(j.title); tbody.insertAdjacentHTML('beforeend',`<tr><td>${{title}}<br><span class="muted">${{esc(j.track||'')}}</span></td><td>${{esc(j.school)}}</td><td>${{esc(j.school_rank||'')}}</td><td>${{esc(j.location||j.state||'')}}</td><td>${{fields}}</td><td>${{esc(j.deadline||'')}}</td><td>${{esc(j.status||'open')}}</td></tr>`);}});}} else {{thead.innerHTML='<tr><th>USN Rank</th><th>School</th><th>Location</th><th>Official</th><th>CS Dept</th><th>CS Jobs</th><th>Faculty Jobs</th></tr>'; SCHOOLS.filter(match).forEach(s=>{{const off=s.official_url?`<a href="${{esc(s.official_url)}}" target="_blank">official</a>`:''; const cs=s.cs_department_url?`<a href="${{esc(s.cs_department_url)}}" target="_blank">CS</a>`:''; const jobs=s.faculty_jobs_url||s.careers_url; const jl=jobs?`<a href="${{esc(jobs)}}" target="_blank">jobs</a>`:''; tbody.insertAdjacentHTML('beforeend',`<tr><td>${{esc(s.usnews_cs_rank)}}</td><td>${{esc(s.school)}}</td><td>${{esc(s.location||s.state)}}</td><td>${{off}}</td><td>${{cs}}</td><td>${{jl}}</td></tr>`);}});}}}}
configure(); render();</script></body></html>'''
    (DOCS/'index.html').write_text(html,encoding='utf-8'); print(f'[OK] wrote {DOCS/"index.html"}')
if __name__=='__main__': main()
